from typing import List

def palindromePairs(words: List[str]) -> List[List[int]]:
    def is_palindrome(s: str) -> bool:
        return s == s[::-1]

    word_map = {word: i for i, word in enumerate(words)}
    result: List[List[int]] = []

    for i, word in enumerate(words):
        # Case 1: full reverse of word exists as another word
        rev = word[::-1]
        if rev in word_map and word_map[rev] != i:
            result.append([i, word_map[rev]])

        # Cases 2 & 3: split word at each position
        for j in range(len(word)):
            # Palindromic prefix -> reversed suffix pairs on the left
            if is_palindrome(word[:j + 1]):
                rev_suffix = word[j + 1:][::-1]
                if rev_suffix in word_map and word_map[rev_suffix] != i:
                    result.append([word_map[rev_suffix], i])

            # Palindromic suffix -> reversed prefix pairs on the right
            if is_palindrome(word[j:]):
                rev_prefix = word[:j][::-1]
                if rev_prefix in word_map and word_map[rev_prefix] != i:
                    result.append([i, word_map[rev_prefix]])

    return result
